code.C:
#include <stdio.h>
#include <math.h>
int gcd(int a, int b) { return b ? gcd(b, a % b) : a; }
int main() { int n; scanf("%d", &n); int a[n]; for (int i = 0; i < n; i++) scanf("%d", &a[i]); int count = 0; for (int i = 0; i < n; i++) for (int j = i + 1; j < n; j++) if (gcd(a[i], a[j]) == 1) count++; printf("%d\n", count); return 0; }

