code.Java:
import java.util.Scanner;
public class Main { public static int gcd(int a, int b) { return b == 0 ? a : gcd(b, a % b); }
public static void main(String[] args) { Scanner scanner = new Scanner(System.in); int n = scanner.nextInt(); int[] a = new int[n]; for (int i = 0; i < n; i++) a[i] = scanner.nextInt(); int count = 0; for (int i = 0; i < n; i++) for (int j = i + 1; j < n; j++) if (gcd(a[i], a[j]) == 1) count++; System.out.println(count); } }

