code.JavaScript:
const readline = require('readline').createInterface({ input: process.stdin, output: process.stdout });
let i = 0;
let n;
let a = [];
readline.on('line', line => {
    if (i == 0) {
        n = parseInt(line);
    } else {
        a = line.split(' ').map(num => parseInt(num));
        let count = 0;
        for (let j = 0; j < n; j++) {
            for (let k = j + 1; k < n; k++) {
                if (gcd(a[j], a[k]) == 1) {
                    count++;
                }
            }
        }
        console.log(count);
        readline.close();
    }
    i++;
});
function gcd(a, b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

